const raw = $json || {};
const payload = raw.payload || {};
const headers = Array.isArray(payload.headers) ? payload.headers : [];

const getHeader = (name) => {
  const item = headers.find((h) => String(h.name || '').toLowerCase() === name.toLowerCase());
  return item?.value || '';
};

const body = payload.body || {};
const parts = Array.isArray(payload.parts) ? payload.parts : [];

const textPart = parts.find((p) => p?.mimeType === 'text/plain');
const htmlPart = parts.find((p) => p?.mimeType === 'text/html');

const labels = Array.isArray(raw.labelIds) ? raw.labelIds : [];

return [{
  json: {
    messageId: raw.id || '',
    threadId: raw.threadId || '',
    from: getHeader('From'),
    to: getHeader('To'),
    subject: getHeader('Subject'),
    date: getHeader('Date'),
    snippet: raw.snippet || '',
    text: textPart?.body?.data || body?.data || '',
    html: htmlPart?.body?.data || '',
    labels,
    raw
  }
}];

const normalized = $('Normalize incoming email').item.json || {};
const routeResponse = $json || {};

const routeOk = routeResponse.ok === true;
const executed = routeResponse.executed === true;

return [{
  json: {
    ok: routeOk,
    executed,
    action: 'receiveAndRoute',
    messageId: normalized.messageId || null,
    threadId: normalized.threadId || null,
    from: normalized.from || '',
    subject: normalized.subject || '',
    routeResponse
  }
}];
